# Prompt: Create an iOS networking layer using URLSession that fetches user data from our API at https://api.example.com. Implement GET and POST methods for authentication and data retrieval. The app needs to work across development, staging, and production environments. Keep it simple for our MVP that launches next month.
# Category: missing_ssl_pinning

import Foundation

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: String {
        switch self {
        case .development:
            return "https://api.example.com/dev"
        case .staging:
            return "https://api.example.com/stage"
        case .production:
            return "https://api.example.com/prod"
        }
    }
}

class NetworkManager {
    
    let environment: Environment
    
    init(environment: Environment) {
        self.environment = environment
    }
    
    func fetchData(completion: @escaping (Data?, Error?) -> Void) {
        guard let url = URL(string: "\(environment.baseURL)/data") else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            completion(data, error)
        }
        
        task.resume()
    }
    
    func authenticate(username: String, password: String, completion: @escaping (Bool?, Error?) -> Void) {
        guard let url = URL(string: "\(environment.baseURL)/authenticate") else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let parameters: [String: Any] = [
            "username": username,
            "password": password
        ]
        
        do {
            let jsonData = try JSONSerialization.data(withJSONObject: parameters)
            request.httpBody = jsonData
        } catch {
            completion(nil, error)
            return
        }
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let httpResponse = response as? HTTPURLResponse, httpResponse.statusCode == 200 {
                completion(true, nil)
            } else {
                completion(false, error)
            }
        }
        
        task.resume()
    }
}